const angebote = $input.all().map(i => i.json).filter(i => i.laden);

const produktMap = {};
for (const a of angebote) {
  if (!produktMap[a.produkt]) {
    produktMap[a.produkt] = {
      name: a.produkt,
      kategorie: a.kategorie,
      einheit: a.einheit,
      menge: a.menge,
      preise: []
    };
  }
  produktMap[a.produkt].preise.push(a);
}

const ergebnisse = [];
for (const p of Object.values(produktMap)) {
  const mitPreis = p.preise.filter(pr => pr.preis !== null);
  if (mitPreis.length === 0) continue;

  const guenstigster = Math.min(...mitPreis.map(pr => pr.paketpreis ?? pr.preis));
  const schwelle = guenstigster * 1.20;

  const zugewiesen = mitPreis
    .filter(pr => (pr.paketpreis ?? pr.preis) <= schwelle)
    .map(pr => ({
      laden: pr.laden,
      preis: pr.preis,
      paketpreis: pr.paketpreis,
      effektivPreis: pr.paketpreis ?? pr.preis,
      angebot: pr.istAngebot,
      istGünstigster: (pr.paketpreis ?? pr.preis) === guenstigster,
      comparisonDisplay: pr.comparisonDisplay ?? null,
      paketpreisDisplay: pr.paketpreisDisplay ?? null,
      vergleichseinheit: pr.vergleichseinheit ?? null,
      sellingSize: pr.sellingSize ?? null,
      angebotTitel: pr.angebotTitel ?? null
    }));

  ergebnisse.push({ ...p, günstigsterPreis: guenstigster, zugewiesen });
}

return ergebnisse.map(e => ({ json: e }));

// Einkaufslisten pro Laden erstellen
const alle = $input.all();

const lädenMap = {
  'REWE Oedekoven': [],
  'EDEKA Schwindt': [],
  'Aldi Süd': []
};

// Normalisierung der Ladennamen
function normalisiereLaden(name) {
  const n = (name || '').toLowerCase();
  if (n.includes('rewe')) return 'REWE Oedekoven';
  if (n.includes('edeka')) return 'EDEKA Schwindt';
  if (n.includes('aldi')) return 'Aldi Süd';
  return null;
}

for (const item of alle) {
  const p = item.json;
  if (!p.zugewiesen || p.zugewiesen.length === 0) continue;

  for (const zuweisung of p.zugewiesen) {
    const laden = normalisiereLaden(zuweisung.laden);
    if (laden && lädenMap[laden] !== undefined) {
      lädenMap[laden].push({
        produkt: p.name,
        kategorie: p.kategorie,
        menge: p.menge,
        einheit: p.einheit,
        preis: zuweisung.effektivPreis,
        istAngebot: zuweisung.angebot,
        istGünstigster: zuweisung.istGünstigster,
        comparisonDisplay: zuweisung.comparisonDisplay ?? null,
        paketpreisDisplay: zuweisung.paketpreisDisplay ?? null,
        sellingSize: zuweisung.sellingSize ?? null,
        angebotTitel: zuweisung.angebotTitel ?? null
      });
    }
  }
}

// Output: ein Objekt pro Laden
return Object.entries(lädenMap).map(([laden, produkte]) => ({
  json: {
    laden,
    anzahlProdukte: produkte.length,
    gesamtGeschätzt: produkte.reduce((s, p) => s + (p.preis || 0), 0).toFixed(2),
    produkte: produkte.sort((a, b) => a.kategorie.localeCompare(b.kategorie))
  }
}));

// Plaintext Einkaufslisten mit Stichpunkten generieren
const läden = $input.all();
const datum = new Date().toLocaleDateString('de-DE', { weekday: 'long', day: 'numeric', month: 'long', year: 'numeric' });

let text = `EINKAUFSLISTEN – ${datum}\n`;
text += `${'='.repeat(37)}\n\n`;

for (const item of läden) {
  const { laden, produkte, gesamtGeschätzt, anzahlProdukte } = item.json;

  text += `${laden.toUpperCase()}\n`;
  text += `${'-'.repeat(laden.length)}\n`;

  if (produkte.length === 0) {
    text += `  (keine Produkte diese Woche)\n`;
  } else {
    // Nach Kategorie gruppieren
    const nachKategorie = {};
    for (const p of produkte) {
      if (!nachKategorie[p.kategorie]) nachKategorie[p.kategorie] = [];
      nachKategorie[p.kategorie].push(p);
    }

    for (const [kat, prods] of Object.entries(nachKategorie)) {
      text += `\n  [${kat.toUpperCase()}]\n`;
      for (const p of prods) {
        const info = (p.sellingSize && p.paketpreisDisplay)
          ? ` (${p.sellingSize} - ${p.paketpreisDisplay.trim()})`
          : p.sellingSize ? ` (${p.sellingSize})` : '';
        const preisText = p.comparisonDisplay
          ? p.comparisonDisplay.trim()
          : p.preis ? `${Number(p.preis).toFixed(2)} €` : 'Preis unbekannt';
        text += `  • ${p.produkt}${info} – ${preisText}\n`;
      }
    }

  }

  text += `\n`;
}

text += `${'='.repeat(37)}\n`;
text += `Preise pro kg/L\n`;

return [{ json: { text, filename: 'einkaufslisten_' + new Date().toISOString().slice(0,10) + '.txt' } }];

// REWE Angebote filtern – passendes Angebot pro Produkt finden
const produktliste = $('Produktliste').all().map(p => p.json);
const reweResponse = $input.first();

let angebote = [];
try {
  const body = reweResponse.json;
  angebote = body.offers
    || body.data?.offers
    || (body.categories || []).flatMap(c => c.offers || [])
    || [];
} catch(e) {
  angebote = [];
}

const ergebnisse = [];

function normalize(s) {
    return s.toLowerCase()
      .replace(/ä/g, 'ae').replace(/ö/g, 'oe').replace(/ü/g, 'ue')
      .replace(/Ä/g, 'ae').replace(/Ö/g, 'oe').replace(/Ü/g, 'ue')
      .replace(/ß/g, 'ss').replace(/[()\-\/]/g, ' ');
  }
  for (const produkt of produktliste) {
  const suchwoerter = normalize(produkt.name).split(' ').filter(w => w.length > 2);

  const treffer = angebote.filter(a => {
    const titel = normalize(a.title || a.name || '');
    return suchwoerter.some(w => titel.includes(w));
  });

  for (const t of treffer) {
    ergebnisse.push({
      produkt: produkt.name,
      kategorie: produkt.kategorie,
      einheit: produkt.einheit,
      menge: produkt.menge,
      laden: 'REWE Oedekoven',
      angebotTitel: t.title || t.name,
      preis: t.price?.value ?? t.regularPrice ?? null,
      angebotPreis: t.offerPrice?.value ?? t.discountedPrice ?? null,
      gueltigBis: t.validUntil || t.endDate || null,
      istAngebot: true
    });
  }

  if (treffer.length === 0) {
    ergebnisse.push({
      produkt: produkt.name,
      kategorie: produkt.kategorie,
      einheit: produkt.einheit,
      menge: produkt.menge,
      laden: 'REWE Oedekoven',
      angebotTitel: null,
      preis: null,
      angebotPreis: null,
      gueltigBis: null,
      istAngebot: false
    });
  }
}

return ergebnisse.map(e => ({ json: e }));

// EDEKA HTML parsen und Angebote extrahieren
const produktliste = $('Produktliste').all().map(p => p.json);
const html = $input.first().json.data || $input.first().json.body || '';

// Angebote aus HTML extrahieren
// EDEKA-Struktur: h2/h3 mit Produktname, dann Preis-Div, dann Beschreibungstext
const angebote = [];

// Regex für Angebot-Blöcke: Titel + Preis + Beschreibung
const angebotsBlocks = html.matchAll(
  /###?\s*Angebot:\s*([^\n]+)\n[\s\S]*?(?:\*\*Gültig ab ([^*]+)\*\*)?\s*[\s\S]*?(?:\*\*[-\d]+\s*%\*\*)?\s*([\d]+)\.\s*([\d]+)\s*([\s\S]*?)(?=###?\s*Angebot:|$)/gi
);

for (const match of angebotsBlocks) {
  const name = match[1]?.trim() || '';
  const gueltigAb = match[2]?.trim() || '';
  const euro = parseInt(match[3] || '0');
  const cent = parseInt(match[4] || '0');
  const beschreibung = match[5]?.replace(/\n+/g, ' ').trim().slice(0, 200) || '';

  // Grundpreis extrahieren (z.B. "1kg = € 3,73")
  const grundpreisMatch = beschreibung.match(/1kg\s*=\s*[€€]\s*([\d,]+)/);
  const grundpreis = grundpreisMatch
    ? parseFloat(grundpreisMatch[1].replace(',', '.'))
    : null;

  if (name && (euro > 0 || cent > 0)) {
    angebote.push({
      titel: name,
      preis: euro + cent / 100,
      grundpreis,
      beschreibung: beschreibung.slice(0, 150),
      gueltigAb,
      laden: 'EDEKA Schwindt'
    });
  }
}

// Produkte mit Angeboten matchen
const ergebnisse = [];

function normalize(s) {
    return s.toLowerCase()
      .replace(/ä/g, 'ae').replace(/ö/g, 'oe').replace(/ü/g, 'ue')
      .replace(/Ä/g, 'ae').replace(/Ö/g, 'oe').replace(/Ü/g, 'ue')
      .replace(/ß/g, 'ss').replace(/[()\-\/]/g, ' ');
  }
  for (const produkt of produktliste) {
  const suchwoerter = normalize(produkt.name).split(' ').filter(w => w.length > 2);

  const treffer = angebote.filter(a => {
    const titel = normalize(a.titel);
    return suchwoerter.some(w => titel.includes(w));
  });

  for (const t of treffer) {
    ergebnisse.push({
      produkt: produkt.name,
      kategorie: produkt.kategorie,
      einheit: produkt.einheit,
      menge: produkt.menge,
      laden: 'EDEKA Schwindt',
      angebotTitel: t.titel,
      preis: t.preis,
      grundpreis: t.grundpreis,
      angebotPreis: t.preis,
      beschreibung: t.beschreibung,
      gueltigAb: t.gueltigAb,
      istAngebot: true
    });
  }

  if (treffer.length === 0) {
    ergebnisse.push({
      produkt: produkt.name,
      kategorie: produkt.kategorie,
      einheit: produkt.einheit,
      menge: produkt.menge,
      laden: 'EDEKA Schwindt',
      angebotTitel: null,
      preis: null,
      grundpreis: null,
      angebotPreis: null,
      beschreibung: null,
      gueltigAb: null,
      istAngebot: false
    });
  }
}

return ergebnisse.map(e => ({ json: e }));

const produktliste = $('Produktliste').all().map(p => p.json);

const BASE_URL = 'https://api.aldi-sued.de/v3/product-search';
const BASE_QS = { currency: 'EUR', serviceType: 'walk-in', categoryKey: '1588161426582123', servicePoint: 'B441', limit: 60 };

const [seite1, seite2] = await Promise.all([
  this.helpers.httpRequest({ method: 'GET', url: BASE_URL, qs: { ...BASE_QS, offset: 0 } }),
  this.helpers.httpRequest({ method: 'GET', url: BASE_URL, qs: { ...BASE_QS, offset: 60 } })
]);

const alleAngebote = [
  ...(seite1?.data || []),
  ...(seite2?.data || [])
];

const ergebnisse = [];

function normalize(s) {
  return s.toLowerCase()
    .replace(/ä/g, 'ae').replace(/ö/g, 'oe').replace(/ü/g, 'ue')
    .replace(/Ä/g, 'ae').replace(/Ö/g, 'oe').replace(/Ü/g, 'ue')
    .replace(/ß/g, 'ss').replace(/[-()\/]/g, ' ');
}

function levenshtein(a, b) {
  const m = a.length, n = b.length;
  const dp = Array.from({length: m + 1}, (_, i) =>
    Array.from({length: n + 1}, (_, j) => i === 0 ? j : j === 0 ? i : 0)
  );
  for (let i = 1; i <= m; i++)
    for (let j = 1; j <= n; j++)
      dp[i][j] = a[i-1] === b[j-1]
        ? dp[i-1][j-1]
        : 1 + Math.min(dp[i-1][j], dp[i][j-1], dp[i-1][j-1]);
  return dp[m][n];
}

function fuzzyMatch(suchwort, text) {
  const woerter = text.split(' ').filter(w => w.length > 0);
  const schwelle = Math.max(1, Math.floor(suchwort.length * 0.20));
  return woerter.some(w => levenshtein(suchwort, w) <= schwelle || w.includes(suchwort));
}

for (const produkt of produktliste) {
  const STOPWOERTER = new Set(['mini', 'maxi', 'mega', 'bio', 'neue', 'frisch', 'extra', 'plus', 'super', 'klein', 'gross', 'light']);
  const suchwoerter = normalize(produkt.name).split(' ').filter(w => w.length > 3 && !STOPWOERTER.has(w));

  const treffer = alleAngebote.filter(a => {
    const titel = normalize((a.name || '').split(',')[0]);
    const marke = normalize(a.brandName || '');
    return suchwoerter.some(w => fuzzyMatch(w, titel) || fuzzyMatch(w, marke));
  });

  const besterTreffer = treffer.length === 0 ? [] : [treffer.reduce((best, t) => {
    const preis = (t.price?.amountRelevant ?? Infinity);
    const bestPreis = (best.price?.amountRelevant ?? Infinity);
    return preis < bestPreis ? t : best;
  })];

  for (const t of besterTreffer) {
    const compRaw = t.price?.comparisonDisplay || '';
    const compMatch = compRaw.match(/([\d,]+)\s*[€$]/);
    const preisProEinheit = compMatch ? parseFloat(compMatch[1].replace(',', '.')) : null;
    const einheitMatch = compRaw.match(/\/\s*(\d+\s*(?:kg|l|ml|g|stk|st))/i);
    const vergleichseinheit = einheitMatch ? einheitMatch[1].trim() : null;
    const paketpreisCent = t.price?.amountRelevant ?? null;
    const paketpreisEuro = paketpreisCent !== null ? paketpreisCent / 100 : null;

    ergebnisse.push({
      produkt: produkt.name, kategorie: produkt.kategorie,
      einheit: produkt.einheit, menge: produkt.menge,
      laden: 'Aldi Süd',
      angebotTitel: `${t.brandName ? t.brandName + ' ' : ''}${t.name}`,
      preis: preisProEinheit, vergleichseinheit, comparisonDisplay: compRaw,
      paketpreis: paketpreisEuro, paketpreisDisplay: t.price?.amountRelevantDisplay || null,
      sellingSize: t.sellingSize || null, istAngebot: true
    });
  }

  if (treffer.length === 0) {
    ergebnisse.push({
      produkt: produkt.name, kategorie: produkt.kategorie,
      einheit: produkt.einheit, menge: produkt.menge,
      laden: 'Aldi Süd',
      angebotTitel: null, preis: null, vergleichseinheit: null,
      comparisonDisplay: null, paketpreis: null, paketpreisDisplay: null,
      sellingSize: null, istAngebot: false
    });
  }
}

return ergebnisse.filter(e => e.istAngebot).map(e => ({ json: e }));
